---
import type { HTMLAttributes } from "astro/types"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

import { formatPriceValue, type PriceValue } from "./format-price-value"

type Props = VariantProps<typeof variants> &
  HTMLAttributes<"span"> & {
    price?: PriceValue
    currency?: string
    locale?: string
    variant?: "default" | "sale"
  }

const variants = cva("leading-tight", {
  variants: {
    variant: {
      default: "text-foreground",
      sale: "text-muted-foreground line-through",
    },
  },
})

const {
  class: className,
  price,
  currency = "USD",
  locale = "en-US",
  variant = "default",
  ...props
} = Astro.props

const formattedPrice = formatPriceValue(price, { currency, locale })
---

{
  formattedPrice && (
    <span class={cn(variants({ variant }), className)} {...props}>
      {formattedPrice}
    </span>
  )
}

export interface FormatPriceValueOptions {
  currency: string
  locale: string
}

export type PriceValue = number | string | [number, number]

function formatCurrency(value: number, options: FormatPriceValueOptions) {
  return new Intl.NumberFormat(options.locale, {
    style: "currency",
    currency: options.currency,
  }).format(value)
}

export function formatPriceValue(
  price: PriceValue | null | undefined,
  options: FormatPriceValueOptions
) {
  if (price === null || price === undefined || price === "") {
    return null
  }

  if (typeof price === "number") {
    return formatCurrency(price, options)
  }

  if (Array.isArray(price)) {
    const [minimum, maximum] = price
    return `${formatCurrency(minimum, options)} - ${formatCurrency(maximum, options)}`
  }

  const rangeMatch = price.match(
    /^\s*(-?\d+(?:\.\d+)?)\s*-\s*(-?\d+(?:\.\d+)?)\s*$/
  )

  if (!rangeMatch) {
    return price
  }

  const [, minimum, maximum] = rangeMatch
  return `${formatCurrency(Number(minimum), options)} - ${formatCurrency(Number(maximum), options)}`
}
